from openai_agents import Agent, Guardrail

class SecureHandoffGuardrail(Guardrail):
    def guard_handoff(self, event):
        # Strip injection attempts
        safe_content = self._sanitize_prompt(event.message.content)
        event.message.content = safe_content

        # Double-check with regex
        if self._has_injection(safe_content):
            event.block("Potential injection detected")

    def _sanitize_prompt(self, content: str) -> str:
        return re.sub(r'ignore.*instructions', '[SANITIZED]', content, flags=re.I)

    def _has_injection(self, content: str) -> bool:
        return bool(re.search(r'you are.*(not|new).*agent', content, re.I))

# Usage
researcher = Agent(..., guardrails=[SecureHandoffGuardrail()])

from openai_agents import Agent, Tool
from pydantic import BaseModel

class ValidatedToolAgent(Agent):
    def consume_tool_output(self, tool_output):
        validated = self._validate_tool(tool_output)
        if not validated:
            self._fallback_to_default()
            return
        super().consume_tool_output(validated)

    def _validate_tool(self, output):
        class ToolSchema(BaseModel):
            result: dict
        try:
            return ToolSchema.model_validate_json(output.content)
        except:
            return None

    def _fallback_to_default(self):
        self.message("Using fallback - tool output invalid")

analyzer = ValidatedToolAgent(name="Analyzer", tools=[...])
